6113	\begin{lemma}\leanok
6114	[{\v C}ech cohomology transports along an isomorphism of coefficients]
6115	  \label{lem:cechCohomology_isZero_of_iso}
6116	  \lean{AlgebraicGeometry.cechCohomology_isZero_of_iso}
6117	  \uses{def:cech_cohomology_accessor, def:section_cech_functoriality}
6118	  \textit{Project-local transport lemma.}
6119	  Let \(U : \iota \to \mathrm{Opens}(X)\) be an index family and let \(e : \mathcal{F} \cong
6120	  \mathcal{G}\) be an isomorphism of presheaves of \(\mathcal{O}_X\)-modules. If
6121	  \(\check{H}^p(\mathcal{U}, \mathcal{F}) = 0\) for some \(p\), then
6122	  \(\check{H}^p(\mathcal{U}, \mathcal{G}) = 0\).
6123	\end{lemma}
6124	\begin{proof}
6125	  \uses{def:section_cech_functoriality}
6126	  \leanok
6127	  The section {\v C}ech complex is functorial in the coefficient presheaf
6128	  (Definition~\ref{def:section_cech_functoriality}), so \(e\) induces an isomorphism of section
6129	  {\v C}ech complexes \(\check{\mathcal{C}}^\bullet(\mathcal{U}, \mathcal{F}) \cong
6130	  \check{\mathcal{C}}^\bullet(\mathcal{U}, \mathcal{G})\), and applying the degree-\(p\) homology
6131	  functor yields an isomorphism \(\check{H}^p(\mathcal{U}, \mathcal{F}) \cong
6132	  \check{H}^p(\mathcal{U}, \mathcal{G})\). A group isomorphic to a zero object is itself zero.
6133	\end{proof}
